function find_largest(inputs: seq<int>): (ret: int)
  requires |inputs| >= 1
  ensures forall x :: x in inputs ==> x <= ret
{
  if |inputs| == 1 then inputs[0]
  else 
    assert 2 <= |inputs|;
    var rest_largest := find_largest(inputs[1..]);
    var ret: int := if inputs[0] >= rest_largest then inputs[0] else rest_largest;
    assert inputs == [inputs[0]] + inputs[1..]; 
    ret 
}

function count_adajacent_duplicates(inputs: seq<int>, i: int): int
  requires 0 <= i < |inputs| - 1
  decreases |inputs| - i
{
  if i + 1 == |inputs| - 1 then if inputs[i] == inputs[i + 1] then 1 else 0
  else if inputs[i] == inputs[i + 1] then 1 + count_adajacent_duplicates(inputs, i + 1)
  else count_adajacent_duplicates(inputs, i + 1)
}

function find_smallest(inputs: seq<int>): (ret: int)
  requires |inputs| >= 1
  ensures forall x :: x in inputs ==> ret <= x 
{
  if |inputs| == 1 then inputs[0]
  else 
    assert 2 <= |inputs|;
    var rest_smallest := find_smallest(inputs[1..]);
    var ret: int := if inputs[0] <= rest_smallest then inputs[0] else rest_smallest;
    assert inputs == [inputs[0]] + inputs[1..]; 
    assert ret == if inputs[0] <= rest_smallest then inputs[0] else rest_smallest;
    ret 
}

function sum_array(inputs: seq<int>): int
{
  if |inputs| == 0 then 0
  else  inputs[0] + sum_array(inputs[1..])
}

function sum_array(inputs: seq<int>, i: int): int
{
  if |inputs| == 0 then 0
  else inputs[0] * i + sum_array(inputs[1..], i * -1)
}

function array_to_set(arr: seq<int>): set<int>
{
  if |arr| == 0 then {}
  else {arr[0]} + array_to_set(arr[1..])
}
